// Build getUpdates request params. OFFSET STORE PLACEHOLDER — test-only demo.
const store = $getWorkflowStaticData('global');
if (store.lastUpdateId === undefined) store.lastUpdateId = 0;
return [{
  json: {
    offset: store.lastUpdateId,
    limit: 10,
    allowed_chat_placeholder: '**CONFIGURE_ALLOWED_CHAT_ID_IN_N8N_UI**',
    offset_store_placeholder: '**CONFIGURE_OFFSET_STORE_IN_N8N_UI**',
    decision_state_store_placeholder: '**CONFIGURE_DECISION_STATE_STORE_IN_N8N_UI**',
    test_only: true
  }
}];

// Normalize getUpdates response into candidate inbound items.
const resp = $input.item.json;
const body = resp && resp.body !== undefined ? resp.body : resp;
const results = body && Array.isArray(body.result) ? body.result : [];
const OPEN = ['D-9998-T'];
const items = [];
for (const u of results) {
  const cq = u.callback_query || {};
  const msg = cq.message || u.message || {};
  const text = String(cq.data || msg.text || '').trim();
  let inbound_kind = 'unknown';
  if (text.startsWith('note:')) inbound_kind = 'note';
  else if (text.startsWith('dp:')) inbound_kind = 'callback';
  else if (/^[123]$/.test(text)) inbound_kind = 'plain_option';
  items.push({
    update_id: u.update_id,
    inbound_kind,
    inbound_text: text,
    chat_id_redacted: 'REDACTED_CHAT_ID',
    user_id_redacted: 'REDACTED_USER_ID',
    message_id: msg.message_id || cq.message?.message_id || null
  });
}
return {
  json: {
    http_ok: body && body.ok === true,
    result_count: results.length,
    candidates: items,
    open_decision_ids: OPEN,
    test_only: true
  }
};

// Filter allowed chat/user placeholder (configure in UI for live gate).
const d = $input.item.json;
const ALLOWED = '**CONFIGURE_ALLOWED_CHAT_ID_IN_N8N_UI**';
const chatConfigured = ALLOWED.indexOf('CONFIGURE') === -1;
return {
  json: {
    ...d,
    chat_filter_ok: chatConfigured,
    block_reason: chatConfigured ? null : 'allowed_chat_not_configured'
  }
};

// Parse Decision Packet response from callback_data or plain 1/2/3.
const d = $input.item.json;
const OPEN = d.open_decision_ids || ['D-9998-T'];
let best = null;
for (const c of d.candidates || []) {
  let decision_id = null;
  let selected_option = null;
  let note_present = false;
  if (c.inbound_kind === 'callback') {
    const m = String(c.inbound_text).match(/^dp:(D-\d{4}-[A-Z]):([123])$/);
    if (m) { decision_id = m[1]; selected_option = m[2]; }
  } else if (c.inbound_kind === 'plain_option' && OPEN.length === 1) {
    decision_id = OPEN[0];
    selected_option = c.inbound_text;
  } else if (c.inbound_kind === 'note') {
    const nm = String(c.inbound_text).match(/^note:(D-\d{4}-[A-Z]):(.+)$/);
    if (nm) {
      decision_id = nm[1];
      note_present = true;
      selected_option = null;
    }
  }
  if (decision_id) {
    best = { ...c, decision_id, selected_option, note_present };
    break;
  }
}
return {
  json: {
    ...d,
    parsed: best,
    parse_ok: !!best
  }
};

// Offset/dedupe/idempotency guard (demo staticData; replace with CONFIGURE_OFFSET_STORE_IN_N8N_UI).
const d = $input.item.json;
const store = $getWorkflowStaticData('global');
if (!store.handledKeys) store.handledKeys = {};
if (store.lastUpdateId === undefined) store.lastUpdateId = 0;
const p = d.parsed;
let status = 'blocked';
let duplicate_or_stale = false;
let block_reason = d.block_reason || 'no_matching_update';
let update_id = null;
let decision_id = null;
let selected_option = null;
let note_present = false;
if (!d.chat_filter_ok) {
  block_reason = d.block_reason || 'allowed_chat_not_configured';
} else if (!p) {
  block_reason = 'no_parseable_decision_response';
} else {
  update_id = p.update_id;
  decision_id = p.decision_id;
  selected_option = p.selected_option;
  note_present = !!p.note_present;
  const open = (d.open_decision_ids || []).includes(decision_id);
  const key = decision_id + ':' + (selected_option || 'note') + ':' + update_id;
  if (!open) {
    duplicate_or_stale = true;
    block_reason = 'stale_or_unknown_decision_id';
  } else if (store.handledKeys[key]) {
    duplicate_or_stale = true;
    block_reason = 'duplicate_or_double_click';
  } else if (p.inbound_kind === 'plain_option' || p.inbound_kind === 'callback') {
    store.handledKeys[key] = new Date().toISOString();
    if (update_id !== null && update_id >= store.lastUpdateId) store.lastUpdateId = update_id + 1;
    status = 'accepted';
    block_reason = null;
  } else if (note_present) {
    status = 'note_placeholder';
    block_reason = null;
  }
}
return {
  json: {
    status,
    decision_id,
    selected_option,
    update_id,
    duplicate_or_stale,
    note_present,
    block_reason,
    offset_after_placeholder: store.lastUpdateId,
    test_only: true
  }
};

// Sanitized polling receipt.
const d = $input.item.json;
return {
  json: {
    inspect_status: d.status,
    decision_id: d.decision_id,
    selected_option: d.selected_option,
    update_id: d.update_id,
    duplicate_or_stale: d.duplicate_or_stale,
    note_present: d.note_present,
    block_reason: d.block_reason,
    offset_after_placeholder: d.offset_after_placeholder,
    test_only: true,
    note: 'Wf polling receipt — sanitize before recording; no raw chat_id or user_id'
  }
};

// Read-only inspect. No secrets.
const d = $input.item.json;
return {
  json: {
    inspect_status: d.inspect_status,
    decision_id: d.decision_id || null,
    selected_option: d.selected_option || null,
    update_id: d.update_id ?? null,
    duplicate_or_stale: d.duplicate_or_stale || false,
    note_present: d.note_present || false,
    test_only: true,
    note: 'Wf polling gate result — sanitize before recording'
  }
};
